boolean"}},{"name":"eventKey","type":{"name":"number"}},{"name":"index","type":{"name":"number"}},{"name":"view","type":{"name":"string"}}] Компонент представляет собой заголовок и контент, который раскрывается при нажатии. ## Примеры Accordion ```tsx
import React from 'react';
import { Accordion, AccordionItem } from '@salutejs/plasma-web';

export function App() {
    return (
        <div>
            <Accordion>
                <AccordionItem title="Как оплатить заправку бонусами СберСпасибо?">После указания деталей заправки нажмите кнопку «К оплате». Откроется окно оплаты, где вы сможете списать бонусы и оплатить ими до 99% стоимости топлива</AccordionItem>
