    import React, { useState } from 'react';
    import { Combobox, ComboboxItemOption } from '@salutejs/plasma-web';

    export function App() {
        const items = [
            {
                value: 'asia',
                label: 'Азия',
                items: [
                    {
                        value: 'china',
                        label: 'Китай',
                        items: [
                            {
                                value: 'beijing',
                                label: 'Пекин',
                            },
                            {
