## Использование с React Hook Form и нативной формой :::caution Использование атрибута  `name` 
Используйте  свойство  `name`  только когда это необходимо. Оно влияет на выходной тип в  `onChange` .
::: Работа с  `react-hook-form`  через  `register` . ```tsx
import React from 'react';
import { useForm, SubmitHandler } from 'react-hook-form';
import { Combobox, Button } from '@salutejs/plasma-web';

export function App() {
    type Inputs = {
        combobox: string,
        comboboxMulti: string[]
    }

    const { register, handleSubmit } = useForm<Inputs>({
        defaultValues: {
            combobox: 'north_america',
            comboboxMulti: ['brazil']
        }
    });

    const onSubmit: SubmitHandler<Inputs> = (data) => {
        console.log(data);
    };

    const items = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
        {
            value: 'south_america',
            label: 'Южная Америка',
            items: [
                {
                    value: 'brazil',
                    label: 'Бразилия',
                },
                {
                    value: 'argentina',
                    label: 'Аргентина',
                },
            ],
        },
    ];

    return (
        <div style={{ display: "flex", gap: "30px", height: "300px" }}>
            <form onSubmit={handleSubmit(onSubmit)} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                <Combobox
                    items={items}
                    {...register('combobox')}
                />
                <Combobox
                    items={items}
                    {...register('comboboxMulti')}
                    multiple
                />
                <Button type="submit">Отправить</Button>
            </form>
        </div>
    );
}
```

