            <Counter count={10} view="accent" />
            <Counter count={10} view="positive" />
            <Counter count={10} view="warning" />
            <Counter count={10} view="negative" />
            <Counter count={10} view="dark" />
            <Counter count={10} view="light" />
        </div>
    );
}
