## Контролируемый вариант компонента Для передачи текущего значения необходимо использовать свойство  `value` .
Чтобы отслеживать изменения, полученные в поле ввода необходимо использовать  `onChangeValue` .
Свойство  `onCommitDate`  вызывается, когда выбор даты сделан с помощью выпадающего календарая
или же в поле ввода введена корректная дата. ```tsx
import React, {useState} from 'react';
import { DatePicker } from '@salutejs/plasma-web';
import { IconDone } from '@salutejs/plasma-icons';

export function App() {
    const [dateValue, setDate] = useState<Date | string | undefined>(new Date());
    const [originalDateValue, setOriginalDate] = useState<Date | string | null | undefined>(new Date());
    const [isoDateValue, setIsoDate] = useState<string | undefined>(new Date().toISOString());

    const handleChangeValue = (
        _: React.SyntheticEvent<HTMLInputElement> | null,
        value?: string,
        originalDate?: Date | string | null,
        isoDate?: string,
    ) => {
        setDate(value);
        setOriginalDate(originalDate);
        setIsoDate(isoDate);
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '3rem'}}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem'}}>
                <p>Значение date: {String(dateValue)}</p>
                <p>Значение originalDate: {String(originalDateValue)}</p>
                <p>Значение isoDate: {isoDateValue}</p>
            </div>

            <DatePicker
                value={dateValue}
                onChangeValue={handleChangeValue}
                onCommitDate={console.log}
                label="Контролируемый DatePicker"
                format="DD.MM.YYYY"
                lang="ru"
                contentRight={<IconDone size="s" />}
                placement="bottom"
                usePortal
                maskWithFormat
            />
        </div>
    );
}
```

Для передачи текущего значения необходимо использовать свойство  `value`  - принимает массив из двух значений.
Чтобы отслеживать изменения, полученные в полях ввода необходимо использовать  `onChangeFirstValue`  и  `onChangeSecondValue`  соответственно.
Свойства  `onCommitFirstDate`  вызывается для первого значения, а  `onCommitSecondDate`  для второго, когда выбор даты сделан с помощью выпадающего календарая
или же в соответствующем поле ввода введена корректная дата. ```tsx
import React, {useState} from 'react';
import { DatePickerRange } from '@salutejs/plasma-web';
import { IconDone } from '@salutejs/plasma-icons';

type DateType = Date | string | undefined | null

export function App() {
    const [dateValue, setDate] = useState<[DateType, DateType]>([new Date(), null]);
    const [originalDateValue, setOriginalDate] = useState<[DateType, DateType]>([new Date(), null]);
    const [isoDateValue, setIsoDate] = useState<[string?, string?]>([new Date().toISOString(), '']);

    const valueSetter = <T extends unknown, P extends React.Dispatch<React.SetStateAction<any>>>(
        value: T,
        sideOfDate: 'start' | 'end',
        setter: P,
    ) => {
        setter((prevValue) => {
            if (sideOfDate === 'start') {
                return [value, prevValue[1]];
            }

            return [prevValue[0], value];
        });
    };

    const handleChangeValue = (sideOfDate: 'start' | 'end') => (
        _: React.SyntheticEvent<HTMLInputElement> | null,
        value?: string,
        originalDate?: Date | string | null,
        isoDate?: string,
    ) => {
        valueSetter(value, sideOfDate, setDate);
        valueSetter(originalDate, sideOfDate, setOriginalDate);
        valueSetter(isoDate, sideOfDate, setIsoDate);
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '3rem' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
                <p>Значение date:<br/> {dateValue.map(String).join(' --- ')}</p>
                <p>Значение originalDate:<br/> {originalDateValue.map(String).join(' --- ')}</p>
                <p>Значение isoDate:<br/> {isoDateValue.join(' --- ')}</p>
            </div>

            <DatePickerRange
                value={dateValue}
                onChangeFirstValue={handleChangeValue('start')}
                onChangeSecondValue={handleChangeValue('end')}
                onCommitFirstDate={console.log}
                onCommitSecondDate={console.log}
                label="Контролируемый RangeDatePicker"
                format="DD.MM.YYYY"
                lang="ru"
                placement="bottom"
                isDoubleCalendar
                usePortal
                maskWithFormat
            />
        </div>
    );
}
```

