## Divider Props (свойства) для компонента Divider: [{"name":"view","type":{"name":"enum","raw":"\"default\" | \"dark\" | \"light\" | \"inverse\"","value":[{"value":"\"default\""},{"value":"\"dark\""},{"value":"\"light\""},{"value":"\"inverse\""}]}},{"name":"size","type":{"name":"enum","raw":"\"m\"","value":[{"value":"\"m\""}]}},{"name":"orientation","type":{"name":"enum","raw":"\"horizontal\" | \"vertical\"","value":[{"value":"\"horizontal\""},{"value":"\"vertical\""}]}},{"name":"length","type":{"name":"string | number"}}] ## Использование Компонент  `Divider`  используется для визуального разделения компонент. ### Ориентация разделителя Ориентация разделителя задается с помощью свойства orientation. Возможные значения свойства orientation: "horizontal" – горизонтальная (по умолчанию); "vertical" – вертикальная; ```tsx
import React from 'react';
import { BodyS, Divider } from '@salutejs/plasma-web';

export function App() {
    const Demo = ({
        orientation = 'horizontal',
        length = '100%',
        beforeText = 'Before',
        afterText = 'After',
    }) => {
        const wrapperStyle = {
            display: "inline-flex",
            gap: "0.5rem",
            alignItems: "center",
            justifyContent: "center",
            flexDirection: orientation === "horizontal" ? "column" : "row"
        }

        return (
            <div style={wrapperStyle}>
                <BodyS>{beforeText}</BodyS>
                <Divider orientation={orientation} length={length} />
                <BodyS>{afterText}</BodyS>
            </div>
        );
    };

    return (
        <div style={{ display: "flex", gap: "2rem" }}>
            <Demo />
            <Demo orientation="vertical" />
        </div>
    );
}
