ault\""}]}},{"name":"size","type":{"name":"enum","raw":"\"m\" | \"s\" | \"l\" | \"xs\" | \"xl\"","value":[{"value":"\"m\""},{"value":"\"s\""},{"value":"\"l\""},{"value":"\"xs\""},{"value":"\"xl\""}]}}] ## Использование Обязательным параметром является только массив  `items` .
Внутри items может быть такой же вложенный массив items. Формат следующий: ```tsx
type Items = Array<{
        /**
         *  Значение у item
         */
        value: string | number;
        /**
         * Метка-подпись к item
         */
