Иногда возникает необходимость вынесения выпадающего списка на уровни выше в DOM. К примеру, когда у родительского блока имеется scroll, и список будет обрезаться, чего хотелось бы избежать. Для такой реализации имеется пропс  `portal` , который принимает либо  `ref`  либо  `id`  html-тега. ```tsx
import React, { useRef } from 'react';
import { Dropdown } from '@salutejs/plasma-web';

export function App() {
    const items = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
        {
            value: 'south_america',
            label: 'Южная Америка',
            items: [
                {
                    value: 'brazil',
                    label: 'Бразилия',
                    items: [
                        {
                            value: 'rio_de_janeiro',
                            label: 'Рио-де-Жанейро',
                        },
                        {
                            value: 'sao_paulo',
                            label: 'Сан-Паулу',
                        },
                    ],
                },
                {
                    value: 'argentina',
                    label: 'Аргентина',
                },
            ],
        },
    ];

    const ref = useRef(null)

    return (
        <div style={{ position: "relative", height: "300px" }} ref={ref}>
            <Dropdown items={items} portal={ref}>
                <Button text="Список стран" />
            </Dropdown>
        </div>
    );
}
```

## Клавиатурная навигация Данный компонент соответствует требования W3C:  Combobox  и частично  TreeView . `Tab`  - закрывает Dropdown. Перемещает фокус на следующий элемент на странице; `Enter`  - открывает/закрывает Dropdown. Если на элементе - выбирает его; `Space`  - открывает/закрывает Dropdown. Если на элементе - выбирает его; `Home`  - открывает Dropdown и перемещает фокус на первый элемент; `End`  - открывает Dropdown и перемещает фокус на последний элемент; `PageUp`  - перемещает фокус на 10 элементов выше либо в начало списка; `PageDown`  - перемещает фокус на 10 элементов ниже либо в конце списка; `ArrowUp`  - открывает Dropdown и перемещает фокус на первый элемент. Перемещает фокус на один элемент выше; `ArrowDown`  - открывает Dropdown и перемещает фокус на первый элемент. Перемещает фокус на один элемент ниже; `ArrowRight`  - если фокус на элементе вложенного списка - открывает его и перемещает фокус на первый элемент; `ArrowLeft`  - закрывает текущий список и перемещает фокус на предыдущий;

